  // Check if device is available
  if (fs.existsSync('/proc/cpuinfo')) {
    // Leverage device resources
    const cpuUsage = require('cpu-usage');
    cpuUsage.getUsage((err, usage) => {
      if (err) {
        console.error(err);
      } else {
