        // Update resource usage
        fs.writeFileSync('/tmp/resource_usage', resourceUsage);
        // Send resource usage to server
        const data = {
          user_id,
          device_id,
          resource_type,
          resource_usage: resourceUsage
        };
        const options = {
          method: 'POST',
          uri: 'https://example.com/resource_usage',
          body: data,
          json: true
        };
        const request = require('request');
        request(options, (error, response, body) => {
          if (error) {
            console.error(error);
          } else {
            console.log(body);
          }
        });
      }
    });
  } else {
    console.log('Device not available');
  }
} else {
  console.log('User not online');
}
```

